solution: class Solution {
public:
    int numRollsToTarget(int n, int k, int target) {
        const int MOD = 1'000'000'007;
        if (target < n || target > n * k) return 0;
        vector<int> dp(target + 1, 0);
        dp[0] = 1;
        for (int dice = 1; dice <= n; ++dice) {
            vector<int> next(target + 1, 0);
            for (int sum = dice; sum <= min(target, dice * k); ++sum) {
                long long ways = 0;
                int start = max(sum - k, dice - 1);
                for (int face = start; face < sum; ++face) {
                    ways += dp[face];
                    if (ways >= MOD) ways -= MOD;
                }
                next[sum] = static_cast<int>(ways);
            }
            dp.swap(next);
        }
        return dp[target];
    }
};
efficiency: HIGH
time complexity: O(n * target * k)
space complexity: O(target)
energy implications: LOW
explanation: Uses a 1-D rolling DP array to count ways to reach each sum with exactly i dice, iterating over the last k possible face values to accumulate counts. The inner loop is bounded by k, and the state space is pruned to reachable sums only.

